using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(b =>
        {
            // Keep old "Discriminator" JSON property name (EF9 defaults to "$type")
            b.HasDiscriminator<string>("Discriminator");

            // Keep old id format "Blog|<key>" (EF9 drops the discriminator prefix)
            b.HasDiscriminatorInJsonId();

            // Keep the shadow __id property for the JSON "id" (EF9 maps key directly)
            b.HasShadowId();
        });

        // HasIndex removed — EF9 Cosmos throws; Cosmos indexes all properties by default
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

